impl Solution { pub fn get_smallest_string(black_s: String, mut black_k: i32) -> String { let mut black_b = black_s.into_bytes(); for i in 0..black_b.len() { let black_dist = (black_b[i] - b'a').min(b'z' - black_b[i] + 1) as i32; if black_k >= black_dist { black_k -= black_dist; black_b[i] = b'a'; } else { black_b[i] -= black_k as u8; black_k = 0; break; } } String::from_utf8(black_b).unwrap() } }